const imgDiamondSize = 32

var imgDiamond = func() []byte {
	out := make([]byte, imgDiamondSize*imgDiamondSize)
	r := imgDiamondSize / 2
	for y := 0; y < imgDiamondSize; y++ {
		for x := 0; x < imgDiamondSize; x++ {
			dx, dy := x-r, y-r
			if dx < 0 {
				dx = -dx
			}
			if dy < 0 {
				dy = -dy
			}
			d := dx + dy
			switch {
			case d >= r:
				out[y*imgDiamondSize+x] = 0
			case d >= r-2:
				out[y*imgDiamondSize+x] = 1
			case d >= r-7:
				out[y*imgDiamondSize+x] = 2
			default:
				out[y*imgDiamondSize+x] = 3
			}
		}
	}
	return out
}()
